<template><div class="page-container"><FilterBar @search="onSearch" @reset="onReset"><a-input v-model:value="f.userId" placeholder="操作人ID" allow-clear style="width:140px"/><a-select v-model:value="f.module" placeholder="模块" allow-clear style="width:120px"><a-select-option value="user">用户</a-select-option><a-select-option value="content">内容</a-select-option><a-select-option value="shop">商城</a-select-option></a-select><a-range-picker v-model:value="f.dateRange" style="width:240px"/></FilterBar><div class="page-card"><DataTable :columns="cols" :data-source="list" :loading="ld" :total="t" v-model:page="p" v-model:page-size="ps"><template #detail="{r}"><a-tooltip :title="r.detail"><span style="color:#3B82F6;cursor:pointer">{{r.detail?.slice(0,30)}}...</span></a-tooltip></template></DataTable></div></div></template>
<script setup lang="ts">import {ref,reactive} from 'vue';import {systemApi} from '@/api/system';import FilterBar from '@/components/common/FilterBar.vue';import DataTable from '@/components/common/DataTable.vue'
const ld=ref(false),list=ref<any[]>([]),t=ref(0),p=ref(1),ps=ref(20);const f=reactive({userId:'',module:undefined as string|undefined,dateRange:undefined as any})
const cols=[{title:'操作人',dataIndex:'username',width:100},{title:'模块',dataIndex:'module',width:80},{title:'操作',dataIndex:'action',width:80},{title:'目标',dataIndex:'target',width:120},{title:'详情',dataIndex:'detail',width:200,slot:'detail'},{title:'IP',dataIndex:'ip',width:120},{title:'时间',dataIndex:'createdAt',width:160}]
async function ft(){ld.value=true;try{const r=await systemApi.getOperationLogs({page:p.value,pageSize:ps.value,...f});list.value=r.data.data.list;t.value=r.data.data.total}catch{}finally{ld.value=false}}
function onSearch(){p.value=1;ft()};function onReset(){f.userId='';f.module=undefined;f.dateRange=undefined;onSearch()}
ft();
</script>
